head.b:skin:
/* ================================================
   CATATAN GURU IPS — V5 GOVERNMENT FUTURISTIC
   Design: Bright Institutional + Futuristic Clean
   By: Catur Pamungkas | Refactored V5
   - Font: Plus Jakarta Sans + Playfair Display
   - Warna terang bersih ala situs pemerintah
   - Aksen futuristik dengan garis dan gradien
   - Lebih ringan, SEO-friendly, semua fitur aktif
================================================ */

/* ========== CSS VARIABLES ========== */
:root {
  /* Government Blue Palette */
  --primary: #1565C0;
  --primary-light: #1E88E5;
  --primary-lighter: #42A5F5;
  --primary-dark: #0D47A1;
  --primary-50: rgba(21,101,192,0.06);
  --primary-100: rgba(21,101,192,0.1);
  --primary-200: rgba(21,101,192,0.18);

  /* Gold Accent (Institutional) */
  --gold: #D4A017;
  --gold-light: #F0C040;
  --gold-100: rgba(212,160,23,0.1);
  --gold-200: rgba(212,160,23,0.2);

  /* Teal Accent (Futuristic) */
  --teal: #00897B;
  --teal-light: #26A69A;
  --teal-100: rgba(0,137,123,0.1);

  /* Red Accent (Alerts/TKP) */
  --red: #C62828;
  --red-100: rgba(198,40,40,0.08);

  /* Gradients */
  --gradient-primary: linear-gradient(135deg, #1565C0 0%, #0D47A1 50%, #1A237E 100%);
  --gradient-gold: linear-gradient(135deg, #D4A017 0%, #F0C040 100%);
  --gradient-teal: linear-gradient(135deg, #00897B 0%, #004D40 100%);
  --gradient-hero: linear-gradient(135deg, #0D47A1 0%, #1565C0 40%, #1A237E 100%);
  --gradient-subtle: linear-gradient(135deg, rgba(21,101,192,0.05) 0%, rgba(0,137,123,0.05) 100%);
  --gradient-card-shine: linear-gradient(135deg, transparent 40%, rgba(255,255,255,0.6) 50%, transparent 60%);

  /* Backgrounds - BRIGHT & CLEAN */
  --bg-body: #F5F7FA;
  --bg-primary: #FFFFFF;
  --bg-secondary: #F8FAFC;
  --bg-card: #FFFFFF;
  --bg-card-hover: #FAFBFE;
  --bg-glass: rgba(255,255,255,0.92);
  --bg-input: #F0F4F8;
  --bg-hero: linear-gradient(135deg, #0D47A1 0%, #1565C0 50%, #1A237E 100%);

  /* Text */
  --text-primary: #1A202C;
  --text-secondary: #4A5568;
  --text-muted: #94A3B8;
  --text-white: #FFFFFF;

  /* Borders */
  --border: #E2E8F0;
  --border-light: #EDF2F7;
  --border-hover: #1565C0;
  --border-focus: rgba(21,101,192,0.4);

  /* Shadows */
  --shadow-xs: 0 1px 2px rgba(0,0,0,0.04);
  --shadow-sm: 0 2px 8px rgba(0,0,0,0.06);
  --shadow-md: 0 4px 16px rgba(0,0,0,0.08);
  --shadow-lg: 0 8px 32px rgba(0,0,0,0.1);
  --shadow-xl: 0 16px 48px rgba(0,0,0,0.12);
  --shadow-primary: 0 4px 16px rgba(21,101,192,0.2);
  --shadow-gold: 0 4px 16px rgba(212,160,23,0.25);
  --shadow-hover: 0 8px 32px rgba(21,101,192,0.15), 0 2px 8px rgba(0,0,0,0.06);

  /* Radius */
  --radius-sm: 6px;
  --radius-md: 10px;
  --radius-lg: 16px;
  --radius-xl: 20px;
  --radius-full: 9999px;

  /* Transitions */
  --ease: cubic-bezier(0.4, 0, 0.2, 1);
  --t-fast: 0.2s var(--ease);
  --t-normal: 0.3s var(--ease);
  --t-slow: 0.5s var(--ease);

  /* Header */
  --header-h: 68px;
}

/* ========== RESET & BASE ========== */
*, *::before, *::after { margin:0; padding:0; box-sizing:border-box; }
html { scroll-behavior:smooth; font-size:16px; -webkit-text-size-adjust:100%; }
body {
  font-family: 'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, sans-serif;
  background: var(--bg-body);
  color: var(--text-primary);
  line-height: 1.7;
  overflow-x: hidden;
  min-height: 100vh;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* Subtle pattern background */
body::before {
  content: '';
  position: fixed;
  inset: 0;
  background:
    radial-gradient(ellipse 60% 40% at 10% 10%, rgba(21,101,192,0.03) 0%, transparent 60%),
    radial-gradient(ellipse 50% 40% at 90% 90%, rgba(0,137,123,0.03) 0%, transparent 60%);
  pointer-events: none;
  z-index: -1;
}

a { color: var(--primary); text-decoration: none; transition: color var(--t-fast); }
a:hover { color: var(--primary-dark); }
h1,h2,h3,h4,h5,h6 { font-family:'Plus Jakarta Sans',sans-serif; font-weight:700; line-height:1.3; color:var(--text-primary); }
img { max-width:100%; height:auto; }
.container { max-width:1280px; margin:0 auto; padding:0 24px; }
.text-gradient {
  background: var(--gradient-primary);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.text-gradient-gold {
  background: var(--gradient-gold);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* ========== READING PROGRESS ========== */
.reading-progress {
  position: fixed;
  top: 0; left: 0;
  height: 3px;
  background: var(--gradient-gold);
  z-index: 9999;
  width: 0%;
  transition: width 0.1s linear;
}

/* ========== HEADER ========== */
#site-header {
  position: fixed;
  top: 0; left: 0; right: 0;
  z-index: 1000;
  height: var(--header-h);
  padding: 0 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--bg-glass);
  backdrop-filter: blur(20px) saturate(180%);
  -webkit-backdrop-filter: blur(20px) saturate(180%);
  border-bottom: 1px solid var(--border);
  transition: all var(--t-normal);
}
#site-header.scrolled {
  height: 56px;
  background: rgba(255,255,255,0.97);
  box-shadow: var(--shadow-md);
}

/* Logo */
.logo-wrapper {
  display: flex;
  align-items: center;
  gap: 12px;
  text-decoration: none;
  flex-shrink: 0;
}
.logo-icon {
  width: 42px; height: 42px;
  background: var(--gradient-primary);
  border-radius: var(--radius-md);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-size: 1.1rem;
  box-shadow: var(--shadow-primary);
  position: relative;
  overflow: hidden;
}
.logo-icon::after {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: linear-gradient(45deg, transparent 40%, rgba(255,255,255,0.15) 50%, transparent 60%);
  animation: shimmer 3s ease-in-out infinite;
}
@keyframes shimmer {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}
.logo .brand-name {
  font-size: 0.95rem;
  font-weight: 800;
  letter-spacing: -0.3px;
  color: var(--primary-dark);
}
.logo .brand-tagline {
  font-size: 0.58rem;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 2.5px;
  margin-top: 1px;
}

/* Nav */
#main-nav { display:flex; align-items:center; }
#main-nav ul { list-style:none; display:flex; gap:2px; }
#main-nav > ul > li { position:relative; }
#main-nav > ul > li > a {
  display: flex;
  align-items: center;
  gap: 7px;
  padding: 10px 14px;
  color: var(--text-secondary);
  font-weight: 600;
  font-size: 0.85rem;
  border-radius: var(--radius-md);
  transition: all var(--t-fast);
  position: relative;
}
#main-nav > ul > li > a::after {
  content: '';
  position: absolute;
  bottom: 2px;
  left: 14px; right: 14px;
  height: 2px;
  background: var(--primary);
  border-radius: 2px;
  transform: scaleX(0);
  transition: transform var(--t-fast);
}
#main-nav > ul > li > a:hover::after { transform: scaleX(1); }
#main-nav > ul > li > a:hover { color: var(--primary); background: var(--primary-50); }
#main-nav > ul > li > a i:first-child { color: var(--primary); font-size:0.78rem; }
#main-nav > ul > li > a .fa-chevron-down { font-size:0.55rem; transition: transform var(--t-fast); }
#main-nav > ul > li:hover > a .fa-chevron-down { transform: rotate(180deg); }

/* Dropdown */
.dropdown {
  position: absolute;
  top: calc(100% + 8px);
  left: 50%; transform: translateX(-50%) translateY(8px);
  min-width: 270px;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-lg);
  padding: 8px;
  opacity: 0; visibility: hidden;
  transition: all var(--t-normal);
  z-index: 100;
}
.dropdown::before {
  content: '';
  position: absolute;
  top: -6px;
  left: 50%;
  transform: translateX(-50%);
  width: 16px; height: 6px;
  background: var(--bg-card);
  border-left: 1px solid var(--border);
  border-right: 1px solid var(--border);
  border-top: none;
  clip-path: polygon(0 0, 100% 0, 50% 100%);
}
#main-nav li:hover .dropdown {
  opacity: 1; visibility: visible;
  transform: translateX(-50%) translateY(0);
}
.dropdown a {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 14px;
  color: var(--text-secondary);
  font-size: 0.85rem;
  font-weight: 500;
  border-radius: var(--radius-sm);
  transition: all var(--t-fast);
}
.dropdown a:hover { background: var(--primary-50); color: var(--primary); transform: translateX(4px); }
.dropdown a i {
  width: 32px; height: 32px;
  background: var(--primary-50);
  border-radius: var(--radius-sm);
  display: flex; align-items: center; justify-content: center;
  color: var(--primary); font-size: 0.85rem;
  flex-shrink: 0;
  transition: all var(--t-fast);
}
.dropdown a:hover i { background: var(--gradient-primary); color: white; }

/* Header Actions */
.header-actions { display:flex; align-items:center; gap:8px; }
.icon-btn {
  width: 38px; height: 38px;
  border-radius: var(--radius-md);
  background: var(--primary-50);
  color: var(--primary);
  border: 1px solid var(--border);
  cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  font-size: 0.9rem;
  transition: all var(--t-fast);
  flex-shrink: 0;
}
.icon-btn:hover { background: var(--gradient-primary); color: white; border-color: transparent; box-shadow: var(--shadow-primary); transform: translateY(-1px); }
.icon-btn.primary { background: var(--gradient-primary); color: white; border: none; }
#mobile-menu-btn { display:none; }

/* ========== HERO SECTION ========== */
#hero-section {
  margin-top: calc(var(--header-h) + 28px);
  padding-bottom: 36px;
}
.hero-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 28px;
  flex-wrap: wrap; gap: 16px;
}
.hero-title-wrapper { display:flex; align-items:center; gap:14px; }
.hero-icon-large {
  width: 52px; height: 52px;
  background: var(--gradient-primary);
  border-radius: var(--radius-lg);
  display: flex; align-items: center; justify-content: center;
  color: white; font-size: 1.4rem;
  box-shadow: var(--shadow-primary);
  flex-shrink: 0;
}
.hero-title {
  font-family: 'Playfair Display', serif;
  font-size: 1.65rem;
  font-weight: 800;
  letter-spacing: -0.5px;
  color: var(--text-primary);
}
.hero-subtitle { font-size: 0.85rem; color: var(--text-muted); margin-top: 3px; }
.hero-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 18px;
}
@media (max-width:1100px) { .hero-grid { grid-template-columns: repeat(2,1fr); } }
@media (max-width:680px) { .hero-grid { grid-template-columns: 1fr; } }

.hero-card {
  position: relative;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 24px;
  display: flex; flex-direction: column; gap: 12px;
  transition: all var(--t-normal);
  overflow: hidden;
  text-decoration: none; color: inherit;
}
.hero-card::before {
  content: '';
  position: absolute; top: 0; left: 0; right: 0;
  height: 3px;
  background: var(--gradient-primary);
  transform: scaleX(0);
  transition: transform var(--t-normal);
  transform-origin: left;
}
.hero-card:hover {
  transform: translateY(-5px);
  box-shadow: var(--shadow-hover);
  border-color: var(--primary-200);
}
.hero-card:hover::before { transform: scaleX(1); }
.hero-card-icon {
  width: 48px; height: 48px;
  background: var(--primary-50);
  border-radius: var(--radius-md);
  display: flex; align-items: center; justify-content: center;
  font-size: 1.35rem; color: var(--primary);
  transition: all var(--t-normal);
  flex-shrink: 0;
}
.hero-card:hover .hero-card-icon { background: var(--gradient-primary); color: white; box-shadow: var(--shadow-primary); }
.hero-card h3 { font-size: 1.05rem; font-weight: 700; }
.hero-card p { font-size: 0.85rem; color: var(--text-secondary); line-height: 1.6; }
.hero-link {
  display: inline-flex; align-items: center; gap: 8px;
  font-weight: 700; font-size: 0.82rem;
  color: var(--primary); margin-top: auto; padding-top: 4px;
}
.hero-link i { transition: transform var(--t-fast); font-size: 0.7rem; }
.hero-card:hover .hero-link i { transform: translateX(5px); }

/* Featured card */
.hero-card.featured {
  background: var(--gradient-primary);
  border: none; color: white;
}
.hero-card.featured .hero-card-icon { background: rgba(255,255,255,0.2); color: white; }
.hero-card.featured h3, .hero-card.featured p { color: white; }
.hero-card.featured .hero-link { color: rgba(255,255,255,0.9); }
.hero-card.featured:hover { box-shadow: 0 8px 32px rgba(13,71,161,0.35); }
.hero-card.featured:hover .hero-card-icon { background: rgba(255,255,255,0.3); }

/* ========== SECTION HEADER ========== */
.section-header { text-align: center; margin-bottom: 40px; }
.section-badge {
  display: inline-flex; align-items: center; gap: 7px;
  padding: 6px 18px;
  background: var(--primary-50);
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  font-size: 0.72rem; font-weight: 700;
  color: var(--primary);
  text-transform: uppercase; letter-spacing: 1.5px;
  margin-bottom: 12px;
}
.section-title {
  font-family: 'Playfair Display', serif;
  font-size: 1.9rem; font-weight: 800;
  letter-spacing: -0.5px; margin-bottom: 10px;
}
.section-desc { font-size: 0.95rem; color: var(--text-secondary); max-width: 540px; margin: 0 auto; }

/* ========== CPNS SECTION ========== */
#cpns-section { padding: 48px 0; }
#cpns-section { background: var(--bg-secondary); border-radius: var(--radius-xl); padding: 48px 32px; margin-bottom: 20px; }
@media (max-width:680px) { #cpns-section { padding: 32px 18px; border-radius: var(--radius-lg); } }

.skd-grid {
  display: grid;
  grid-template-columns: repeat(3,1fr);
  gap: 18px; margin-bottom: 32px;
}
@media (max-width:900px) { .skd-grid { grid-template-columns: repeat(2,1fr); } }
@media (max-width:580px) { .skd-grid { grid-template-columns: 1fr; } }

.skd-card {
  position: relative;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 28px 22px;
  text-align: center;
  transition: all var(--t-normal);
  overflow: hidden;
  display: flex; flex-direction: column;
  text-decoration: none; color: inherit;
}
.skd-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; }
.skd-card.twk::before { background: var(--gradient-primary); }
.skd-card.tiu::before { background: var(--gradient-teal); }
.skd-card.tkp::before { background: linear-gradient(90deg, #C62828, #E53935); }
.skd-card:hover { transform: translateY(-5px); box-shadow: var(--shadow-hover); border-color: var(--primary-200); }

.skd-icon {
  width: 66px; height: 66px;
  margin: 0 auto 16px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 1.6rem;
  flex-shrink: 0;
}
.skd-card.twk .skd-icon { background: var(--primary-50); color: var(--primary); }
.skd-card.tiu .skd-icon { background: var(--teal-100); color: var(--teal); }
.skd-card.tkp .skd-icon { background: var(--red-100); color: var(--red); }
.skd-card h3 { font-size: 1.25rem; font-weight: 800; margin-bottom: 4px; }
.skd-card .skd-full { font-size: 0.75rem; color: var(--text-muted); margin-bottom: 10px; text-transform: uppercase; letter-spacing: 0.5px; }
.skd-card p { font-size: 0.85rem; color: var(--text-secondary); margin-bottom: 16px; flex-grow: 1; line-height: 1.6; }
.skd-stats { display: flex; justify-content: center; gap: 20px; padding-top: 14px; border-top: 1px solid var(--border); }
.skd-stats span { font-size: 0.8rem; color: var(--text-muted); }
.skd-stats strong { color: var(--primary); font-weight: 700; }

/* ========== SPONSOR SECTION ========== */
#sponsor-section { padding: 48px 0; }
.sponsor-grid { display: grid; grid-template-columns: repeat(4,1fr); gap: 18px; }
@media (max-width:1100px) { .sponsor-grid { grid-template-columns: repeat(2,1fr); } }
@media (max-width:580px) { .sponsor-grid { grid-template-columns: 1fr; } }

.sponsor-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 24px 20px;
  text-align: center;
  transition: all var(--t-normal);
  display: flex; flex-direction: column;
  position: relative; overflow: hidden;
}
.sponsor-card:hover { transform: translateY(-4px); box-shadow: var(--shadow-hover); border-color: var(--primary-200); }
.sponsor-icon {
  width: 60px; height: 60px;
  margin: 0 auto 12px;
  background: var(--gradient-primary);
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 1.5rem; color: white;
  box-shadow: var(--shadow-primary);
}
.sponsor-card h3 { font-size: 1rem; margin-bottom: 6px; }
.sponsor-card p { font-size: 0.82rem; color: var(--text-secondary); margin-bottom: 14px; flex-grow: 1; line-height: 1.55; }
.sponsor-cta {
  display: inline-block;
  padding: 8px 20px;
  background: var(--primary-50);
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  color: var(--primary);
  font-size: 0.8rem; font-weight: 700;
  transition: all var(--t-fast);
}
.sponsor-cta:hover { background: var(--gradient-primary); color: white; border-color: transparent; box-shadow: var(--shadow-primary); }

/* ========== CONTENT WRAPPER ========== */
#content-wrapper {
  display: grid;
  grid-template-columns: 1fr;
  gap: 24px;
  padding: 24px 0;
}
@media (min-width:1100px) { #content-wrapper { grid-template-columns: 1fr 340px; } }

body.item-view #content-wrapper,
body.static-view #content-wrapper {
  display: block;
  max-width: 860px;
  margin: 0 auto;
  padding: 32px 0;
}
body.item-view #sidebar,
body.static-view #sidebar { display: none !important; }

body.item-view .post-card { padding: 36px 44px; border-radius: var(--radius-xl); }
body.item-view .post-title { font-size: 2rem; line-height: 1.25; margin-bottom: 14px; }
body.item-view .post-meta { font-size: 0.88rem; margin-bottom: 22px; padding-bottom: 18px; border-bottom: 1px solid var(--border); }
body.item-view .post-body { font-size: 1.05rem; line-height: 1.9; max-width: 76ch; margin: 0 auto; }
@media (max-width: 900px) {
  body.item-view .post-card { padding: 24px 24px; }
  body.item-view .post-title { font-size: 1.55rem; }
  body.item-view .post-body { font-size: 1rem; max-width: 100%; }
}
@media (max-width: 580px) {
  body.item-view .post-card { padding: 18px 16px; }
  body.item-view .post-title { font-size: 1.3rem; }
}

/* ========== POST CARD ========== */
.post-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 26px;
  margin-bottom: 20px;
  transition: all var(--t-normal);
  position: relative;
  overflow: hidden;
}
.post-card:hover { box-shadow: var(--shadow-hover); border-color: var(--primary-200); }
.post-card::after {
  content: '';
  position: absolute; left: 0; top: 0; bottom: 0;
  width: 3px;
  background: var(--gradient-primary);
  transform: scaleY(0);
  transition: transform var(--t-normal);
}
.post-card:hover::after { transform: scaleY(1); }

.badge {
  display: inline-flex; align-items: center; gap: 5px;
  padding: 4px 12px;
  background: var(--primary-50);
  color: var(--primary);
  border-radius: var(--radius-full);
  font-size: 0.7rem; font-weight: 700;
  text-transform: uppercase; letter-spacing: 0.5px;
  border: 1px solid var(--border);
}
.badge::before { content: ''; width: 5px; height: 5px; background: var(--primary); border-radius: 50%; }

/* Post Card List */
.post-card-list { padding: 0; overflow: hidden; display: flex; flex-direction: column; }
.post-thumbnail-link { display: block; overflow: hidden; border-radius: var(--radius-xl) var(--radius-xl) 0 0; }
.post-thumbnail {
  width: 100%; height: 200px;
  object-fit: cover; display: block;
  transition: transform 0.5s var(--ease);
}
.post-card-list:hover .post-thumbnail { transform: scale(1.03); }

.post-thumbnail-generated {
  display: flex; flex-direction: column;
  align-items: center; justify-content: center;
  width: 100%; height: 200px;
  background: var(--gradient-hero);
  position: relative; overflow: hidden; gap: 8px;
  border-radius: var(--radius-xl) var(--radius-xl) 0 0;
  text-decoration: none; padding: 20px;
  transition: all var(--t-normal);
}
.post-thumbnail-generated::before {
  content: '';
  position: absolute; inset: 0;
  background:
    radial-gradient(ellipse 80% 60% at 20% 20%, rgba(255,255,255,0.08) 0%, transparent 60%),
    radial-gradient(ellipse 60% 50% at 80% 80%, rgba(212,160,23,0.1) 0%, transparent 60%);
  pointer-events: none;
}
.post-card-list:hover .post-thumbnail-generated { filter: brightness(1.05); }
.post-thumb-icon {
  font-size: 2.5rem;
  color: rgba(255,255,255,0.9);
  z-index: 1;
  filter: drop-shadow(0 0 10px rgba(255,255,255,0.3));
  order: 1;
}
.post-thumb-label {
  font-size: 0.65rem; font-weight: 700;
  letter-spacing: 0.12em; text-transform: uppercase;
  color: var(--gold-light); z-index: 1;
  background: rgba(212,160,23,0.25);
  border: 1px solid rgba(212,160,23,0.5);
  padding: 3px 12px; border-radius: 999px;
  order: 0;
}
.post-thumb-title {
  font-size: 0.82rem; font-weight: 600; color: rgba(255,255,255,0.85);
  text-align: center; z-index: 1; line-height: 1.5;
  display: -webkit-box; -webkit-line-clamp: 2;
  -webkit-box-orient: vertical; overflow: hidden;
  max-width: 90%; order: 2;
}
@media (max-width:768px) { .post-thumbnail-generated { height: 160px; } }

.post-card-content { padding: 22px 24px 24px; }
.post-title-list { font-size: 1.3rem !important; margin-top: 8px; }
.post-snippet {
  color: var(--text-secondary);
  margin-bottom: 16px; line-height: 1.7;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
  font-size: 0.9rem;
}
@media (max-width:768px) {
  .post-thumbnail { height: 160px; }
  .post-card-content { padding: 16px; }
  .post-title-list { font-size: 1.15rem !important; }
}

/* Post Title + Meta */
.post-title {
  font-family: 'Playfair Display', serif;
  font-size: 1.8rem; font-weight: 800;
  margin: 12px 0 8px;
  line-height: 1.2; letter-spacing: -0.5px;
}
.post-title a { color: var(--text-primary); }
.post-title a:hover { color: var(--primary); }

.post-meta {
  display: flex; flex-wrap: wrap; gap: 16px;
  font-size: 0.8rem; color: var(--text-muted);
  margin-bottom: 20px;
  padding-bottom: 16px;
  border-bottom: 1px solid var(--border);
}
.post-meta span { display: flex; align-items: center; gap: 6px; }
.post-meta i { font-size: 0.75rem; color: var(--primary); }

/* ========== POST HERO IMAGE ========== */
.post-hero-img {
  width: 100%; margin: 24px 0 32px;
  border-radius: var(--radius-lg);
  overflow: hidden;
  box-shadow: var(--shadow-lg);
}
.post-hero-img-el {
  width: 100%; max-height: 520px;
  object-fit: cover; display: block;
  border-radius: var(--radius-lg);
  margin: 0;
}
.post-hero-generated {
  display: flex; flex-direction: column;
  align-items: center; justify-content: center;
  min-height: 280px; gap: 12px; padding: 36px 24px;
  background: var(--gradient-hero);
  position: relative;
  border-radius: var(--radius-lg);
}
.post-hero-generated::before {
  content: '';
  position: absolute; inset: 0;
  background:
    radial-gradient(ellipse 70% 60% at 15% 15%, rgba(255,255,255,0.06) 0%, transparent 60%),
    radial-gradient(ellipse 55% 50% at 85% 85%, rgba(212,160,23,0.08) 0%, transparent 60%);
  pointer-events: none;
}
.post-hero-label {
  font-size: 0.7rem; font-weight: 700;
  letter-spacing: 0.14em; text-transform: uppercase;
  color: var(--gold-light); z-index: 1;
  background: rgba(212,160,23,0.25);
  border: 1px solid rgba(212,160,23,0.5);
  padding: 4px 16px; border-radius: 999px;
}
.post-hero-icon {
  font-size: 3.2rem; z-index: 1;
  color: rgba(255,255,255,0.9);
  filter: drop-shadow(0 0 16px rgba(255,255,255,0.3));
}
.post-hero-title {
  font-size: 1rem; font-weight: 700; color: rgba(255,255,255,0.85);
  text-align: center; z-index: 1; line-height: 1.5;
  max-width: 80%;
}
@media (max-width: 768px) {
  .post-hero-img-el { max-height: 240px; }
  .post-hero-generated { min-height: 200px; }
  .post-hero-icon { font-size: 2.5rem; }
}

/* ========== POST BODY ========== */
.post-body { font-size: 1rem; line-height: 1.85; color: var(--text-secondary); overflow-wrap: break-word; word-wrap: break-word; }
.post-body p { margin-bottom: 14px; }
.post-body h2 {
  font-family: 'Playfair Display', serif;
  font-size: 1.35rem; font-weight: 700;
  margin: 28px 0 10px; color: var(--primary-dark);
  padding-bottom: 8px;
  border-bottom: 2px solid var(--primary-50);
}
.post-body h3 { font-size: 1.15rem; font-weight: 700; margin: 22px 0 8px; color: var(--text-primary); }
.post-body h4,.post-body h5,.post-body h6 { font-weight: 600; margin: 16px 0 6px; color: var(--text-primary); }
.post-body ul,.post-body ol { margin: 12px 0; padding-left: 24px; }
.post-body li { margin-bottom: 6px; color: var(--text-secondary); }
.post-body li::marker { color: var(--primary); }
.post-body img { max-width: 100% !important; height: auto !important; border-radius: var(--radius-md); margin: 16px auto; display: block; box-shadow: var(--shadow-sm); border: 1px solid var(--border); }
.post-body figure { margin: 20px 0; text-align: center; }
.post-body figcaption { font-size: 0.8rem; color: var(--text-muted); margin-top: 6px; font-style: italic; }
.post-body a { color: var(--primary); border-bottom: 1px dotted var(--primary); }
.post-body a:hover { color: var(--primary-dark); border-bottom-style: solid; }
.post-body blockquote {
  margin: 20px 0; padding: 16px 20px;
  background: var(--primary-50);
  border-left: 3px solid var(--primary);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
  font-style: italic; color: var(--text-secondary);
}
.post-body blockquote p { margin-bottom: 0; }
.post-body pre {
  background: #1A202C;
  color: #E2E8F0;
  padding: 18px; border-radius: var(--radius-md);
  overflow-x: auto; margin: 14px 0;
  border: 1px solid #2D3748;
  font-size: 0.88rem;
  -webkit-overflow-scrolling: touch;
  word-wrap: normal; word-break: normal; white-space: pre; max-width: 100%;
}
.post-body code { background: var(--primary-50); padding: 2px 6px; border-radius: 4px; font-size: 0.88em; font-family: 'Fira Code', 'Courier New', monospace; color: var(--primary-dark); }
.post-body pre code { background: transparent; padding: 0; color: inherit; }
.post-body hr { border: none; height: 2px; background: var(--gradient-primary); margin: 24px 0; opacity: 0.2; border-radius: 2px; }
.post-body table { width: 100% !important; border-collapse: collapse; margin: 20px 0; font-size: 0.9rem; overflow-x: auto; display: block; border: 1px solid var(--border); border-radius: var(--radius-md); -webkit-overflow-scrolling: touch; }
.post-body table thead { background: var(--primary-50); }
.post-body table th { padding: 10px 14px; text-align: left; font-weight: 700; color: var(--primary-dark); border-bottom: 2px solid var(--primary-200); white-space: nowrap; }
.post-body table td { padding: 10px 14px; border-bottom: 1px solid var(--border-light); color: var(--text-secondary); vertical-align: top; }
.post-body table tr:last-child td { border-bottom: none; }
.post-body table tr:hover td { background: var(--primary-50); }
.post-body iframe,.post-body embed,.post-body object { max-width: 100%; }
.post-body .separator { text-align: center; margin: 16px 0; }

/* ========== PAGER ========== */
.blog-pager {
  display: flex; justify-content: center; align-items: center;
  gap: 12px; padding: 24px 0; flex-wrap: wrap;
}
.blog-pager a {
  display: inline-flex; align-items: center; gap: 8px;
  padding: 10px 22px;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  color: var(--text-secondary);
  font-weight: 600; font-size: 0.85rem;
  transition: all var(--t-fast);
}
.blog-pager a:hover { background: var(--gradient-primary); color: white; border-color: transparent; box-shadow: var(--shadow-primary); }
.home-link { background: var(--primary-50); color: var(--primary); }

/* ========== SIDEBAR ========== */
#sidebar { display: flex; flex-direction: column; gap: 18px; }
.sidebar-widget {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 20px;
  transition: box-shadow var(--t-normal);
  position: relative;
  overflow: hidden;
}
.sidebar-widget::before {
  content: '';
  position: absolute; top: 0; left: 0; right: 0;
  height: 3px;
  background: var(--gradient-primary);
}
.sidebar-widget:hover { box-shadow: var(--shadow-md); }
.widget-title {
  font-size: 0.7rem; font-weight: 800;
  text-transform: uppercase; letter-spacing: 1.5px;
  color: var(--primary);
  margin-bottom: 16px; padding-bottom: 10px;
  border-bottom: 1px solid var(--border);
  display: flex; align-items: center; gap: 8px;
}

/* Profile Widget */
.profile-widget { text-align: center; padding: 24px 20px; }
.profile-avatar-wrapper { position: relative; width: 90px; height: 90px; margin: 0 auto 12px; }
.profile-avatar {
  width: 90px; height: 90px;
  border-radius: 50%;
  border: 3px solid var(--primary);
  box-shadow: 0 0 0 4px var(--primary-50), var(--shadow-sm);
  display: block; object-fit: cover;
  transition: transform var(--t-normal);
}
.profile-avatar-wrapper::after {
  content: '';
  position: absolute; inset: -6px;
  border: 2px dashed var(--primary-200);
  border-radius: 50%;
  animation: spin 20s linear infinite;
  pointer-events: none;
}
@keyframes spin { 100% { transform: rotate(360deg); } }
.profile-avatar:hover { transform: scale(1.04); }
.profile-name { font-size: 1rem; font-weight: 700; margin-bottom: 4px; }
.profile-badge {
  display: inline-block;
  padding: 4px 14px;
  background: var(--gradient-primary);
  color: white; border-radius: var(--radius-full);
  font-size: 0.68rem; font-weight: 700;
  margin-bottom: 8px;
}
.profile-bio { font-size: 0.82rem; color: var(--text-secondary); line-height: 1.55; margin-bottom: 12px; }

/* Social Links */
.social-links {
  display: flex; justify-content: center; flex-wrap: wrap; gap: 8px;
  padding-top: 12px; border-top: 1px solid var(--border);
}
.social-link {
  width: 36px; height: 36px;
  border-radius: var(--radius-md);
  background: var(--primary-50);
  border: 1px solid var(--border);
  display: flex; align-items: center; justify-content: center;
  color: var(--primary); font-size: 0.95rem;
  transition: all var(--t-fast);
}
.social-link:hover { background: var(--gradient-primary); color: white; border-color: transparent; transform: translateY(-2px) scale(1.05); box-shadow: var(--shadow-primary); }
.social-link.facebook:hover { background: #1877f2; box-shadow: 0 4px 12px rgba(24,119,242,0.3); }
.social-link.instagram:hover { background: linear-gradient(135deg, #f09433, #e6683c, #dc2743, #bc1888); }
.social-link.youtube:hover { background: #ff0000; box-shadow: 0 4px 12px rgba(255,0,0,0.3); }
.social-link.whatsapp:hover { background: #25d366; box-shadow: 0 4px 12px rgba(37,211,102,0.3); }
.social-link.threads:hover { background: #000; }

/* Stats Grid */
.stats-grid { display: grid; grid-template-columns: repeat(2,1fr); gap: 10px; }
.stat-item {
  text-align: center; padding: 14px 8px;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  transition: all var(--t-fast);
}
.stat-item:hover { background: var(--primary-50); border-color: var(--primary-200); }
.stat-number {
  font-size: 1.35rem; font-weight: 800;
  color: var(--primary);
  display: block; line-height: 1.2;
}
.stat-label { font-size: 0.68rem; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.5px; margin-top: 2px; }

/* Quick Links */
.quick-links { list-style: none; }
.quick-links li { margin-bottom: 6px; }
.quick-links a {
  display: flex; align-items: center; gap: 10px;
  padding: 9px 12px;
  background: var(--bg-secondary);
  border: 1px solid transparent;
  border-radius: var(--radius-sm);
  color: var(--text-secondary);
  font-size: 0.85rem;
  transition: all var(--t-fast);
}
.quick-links a:hover { background: var(--primary-50); border-color: var(--primary-200); color: var(--primary); transform: translateX(4px); }
.quick-links a i {
  width: 28px; height: 28px;
  background: var(--primary-50);
  border-radius: var(--radius-sm);
  display: flex; align-items: center; justify-content: center;
  color: var(--primary); font-size: 0.8rem;
  flex-shrink: 0;
  transition: all var(--t-fast);
}
.quick-links a:hover i { background: var(--gradient-primary); color: white; }

/* Tags Cloud */
.tags-cloud { display: flex; flex-wrap: wrap; gap: 6px; }
.tag-link {
  padding: 5px 12px;
  background: var(--primary-50);
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  font-size: 0.75rem; color: var(--text-secondary);
  transition: all var(--t-fast);
}
.tag-link:hover { background: var(--gradient-primary); color: white; border-color: transparent; }

/* ========== SHARE BUTTONS ========== */
.share-container {
  background: var(--bg-secondary);
  padding: 20px; margin: 24px 0;
  border-radius: var(--radius-lg);
  border: 1px solid var(--border);
  border-left: 4px solid var(--primary);
}
.share-container .share-title { font-weight: 700; color: var(--text-primary); font-size: 0.9rem; margin-bottom: 12px; }
.social-flex { display: flex; flex-wrap: wrap; gap: 8px; }
.btn-share {
  display: inline-flex; align-items: center; justify-content: center;
  padding: 9px 16px; border-radius: var(--radius-full);
  font-size: 0.82rem; font-weight: 700;
  text-decoration: none !important; color: white !important;
  transition: all var(--t-fast); cursor: pointer; border: none; gap: 6px;
}
.btn-share:hover { transform: translateY(-2px); box-shadow: var(--shadow-md); filter: brightness(1.1); }
.btn-share.wa { background: #25D366; }
.btn-share.fb { background: #4267B2; }
.btn-share.x-twitter { background: #000; }
.btn-share.linkedin { background: #0077b5; }
.btn-share.copy-link { background: #475569; }
.btn-share.copy-success { background: #10b981 !important; }

/* ========== COMMENTS ========== */
.comments-section { margin-top: 32px; padding-top: 24px; border-top: 1px solid var(--border); }
.comments-section-title { font-size: 1.1rem; margin-bottom: 18px; display: flex; align-items: center; gap: 10px; }
.comments-section-title i { color: var(--primary); }
.comments-info {
  padding: 12px 16px;
  background: var(--primary-50);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  margin-bottom: 18px;
  font-size: 0.85rem; color: var(--text-secondary);
}
.comments-info i { color: var(--primary); margin-right: 6px; }
#comments { clear: both; }
.comments {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 20px; margin-top: 16px;
}
.comments .comments-content { margin-bottom: 20px; }
.comments h3.title {
  font-size: 1rem; margin-bottom: 16px;
  color: var(--text-primary);
  padding-bottom: 10px; border-bottom: 1px solid var(--border);
}
.comments .comment { margin-bottom: 20px; clear: both; overflow: hidden; }
.comments .comment .comment { margin-left: 50px; margin-top: 16px; padding-left: 16px; border-left: 2px solid var(--border); }
.comments .comment-block {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  padding: 16px; margin-left: 48px; margin-bottom: 12px;
}
.comments .comment-author { font-weight: 700; margin-bottom: 6px; font-size: 0.88rem; }
.comments .comment-author a { color: var(--primary); }
.comments .comment-body { color: var(--text-secondary); font-size: 0.88rem; line-height: 1.6; }
.comments .comment-body.deleted { color: var(--text-muted); font-style: italic; }
.comments .comment-footer { margin-top: 8px; font-size: 0.75rem; }
.comments .comment-timestamp a { color: var(--text-muted); }
.comments .comment-timestamp a:hover { color: var(--primary); }
.comments .avatar-image-container { float: left; margin-right: 10px; }
.comments .avatar-image-container img { width: 40px; height: 40px; border-radius: 50%; border: 2px solid var(--border); }
.comments .continue a,.comments .loadmore a {
  display: inline-flex; align-items: center; gap: 6px;
  padding: 9px 18px;
  background: var(--primary-50);
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  color: var(--primary); font-size: 0.8rem; font-weight: 600;
  transition: all var(--t-fast);
}
.comments .continue a:hover,.comments .loadmore a:hover { background: var(--gradient-primary); color: white; border-color: transparent; }
.comments .loadmore { text-align: center; margin-top: 18px; }
.comment-form {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 20px; margin-top: 20px;
}
.comment-form h4 { font-size: 0.9rem; margin-bottom: 12px; color: var(--primary); }
.comment-form iframe { width: 100%; min-height: 260px; border: none; border-radius: var(--radius-md); background: transparent; }
.item-control { display: inline-block; margin-left: 8px; }
.comment-delete { opacity: 0.5; transition: opacity var(--t-fast); }
.comment-delete:hover { opacity: 1; }
.comment-delete img { width: 13px; height: 13px; }
.no-comments { text-align: center; padding: 32px 18px; color: var(--text-muted); }
.no-comments i { font-size: 2.2rem; margin-bottom: 10px; opacity: 0.3; display: block; }

/* ========== FOOTER ========== */
#site-footer {
  background: var(--gradient-hero);
  border-top: none;
  padding: 60px 0 24px;
  margin-top: 48px;
  position: relative;
  color: rgba(255,255,255,0.85);
}
#site-footer::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 4px; background: var(--gradient-gold); }
.footer-grid {
  display: grid;
  grid-template-columns: 2fr repeat(3,1fr);
  gap: 36px; margin-bottom: 36px;
}
@media (max-width:1100px) { .footer-grid { grid-template-columns: 1fr 1fr; gap: 24px; } }
@media (max-width:580px) { .footer-grid { grid-template-columns: 1fr; } }

.footer-brand h3 {
  font-family: 'Playfair Display', serif;
  font-size: 1.2rem; margin-bottom: 10px;
  color: white;
}
.footer-brand p { font-size: 0.85rem; color: rgba(255,255,255,0.7); line-height: 1.6; margin-bottom: 16px; }
.footer-social { display: flex; gap: 8px; flex-wrap: wrap; }
.footer-social a {
  width: 38px; height: 38px;
  background: rgba(255,255,255,0.12);
  border: 1px solid rgba(255,255,255,0.2);
  border-radius: var(--radius-md);
  display: flex; align-items: center; justify-content: center;
  color: rgba(255,255,255,0.85); font-size: 0.95rem;
  transition: all var(--t-fast);
}
.footer-social a:hover { background: var(--gradient-gold); color: white; border-color: transparent; transform: translateY(-2px); box-shadow: var(--shadow-gold); }
.footer-links h4 {
  font-size: 0.7rem; font-weight: 800;
  text-transform: uppercase; letter-spacing: 1.5px;
  color: var(--gold-light); margin-bottom: 16px;
}
.footer-links ul { list-style: none; }
.footer-links li { margin-bottom: 8px; }
.footer-links a { color: rgba(255,255,255,0.7); font-size: 0.85rem; display: flex; align-items: center; gap: 7px; transition: all var(--t-fast); }
.footer-links a:hover { color: white; transform: translateX(3px); }
.footer-links a i { font-size: 0.6rem; opacity: 0; transition: opacity var(--t-fast); }
.footer-links a:hover i { opacity: 1; }
.copyright {
  text-align: center;
  padding-top: 24px; border-top: 1px solid rgba(255,255,255,0.15);
  font-size: 0.8rem; color: rgba(255,255,255,0.6);
}
.copyright i.fa-heart { color: var(--gold-light); animation: heartbeat 1.5s ease infinite; }
@keyframes heartbeat { 0%,100% { transform: scale(1); } 50% { transform: scale(1.2); } }

/* ========== SEARCH OVERLAY ========== */
#search-overlay {
  position: fixed; inset: 0;
  background: rgba(26,32,44,0.85);
  backdrop-filter: blur(12px);
  z-index: 2000;
  display: none; align-items: flex-start; justify-content: center;
  padding-top: 110px;
  opacity: 0; transition: opacity var(--t-normal);
}
#search-overlay.active { opacity: 1; }
#search-box {
  background: var(--bg-card);
  padding: 28px;
  border-radius: var(--radius-xl);
  width: 92%; max-width: 560px;
  border: 1px solid var(--border);
  box-shadow: var(--shadow-xl);
  position: relative;
  transform: translateY(16px);
  transition: transform var(--t-normal);
}
#search-overlay.active #search-box { transform: translateY(0); }
#search-close { position: absolute; top: 14px; right: 18px; font-size: 1.2rem; cursor: pointer; color: var(--text-muted); transition: all var(--t-fast); }
#search-close:hover { color: var(--primary); transform: rotate(90deg); }
#search-box h3 { font-size: 1.1rem; margin-bottom: 18px; display: flex; align-items: center; gap: 10px; }
#search-box h3 i { color: var(--primary); }
.filter-btns { display: flex; gap: 8px; margin-bottom: 16px; flex-wrap: wrap; }
.filter-btn {
  padding: 7px 14px;
  border: 1px solid var(--border);
  background: transparent;
  color: var(--text-secondary);
  border-radius: var(--radius-full);
  cursor: pointer; font-size: 0.8rem; font-weight: 600;
  transition: all var(--t-fast);
}
.filter-btn:hover { border-color: var(--primary); color: var(--primary); }
.filter-btn.active { background: var(--gradient-primary); color: white; border-color: transparent; }
.search-input-box { display: flex; gap: 10px; }
.search-input-box input {
  flex: 1; padding: 12px 16px;
  border: 2px solid var(--border);
  border-radius: var(--radius-md);
  background: var(--bg-input);
  color: var(--text-primary); font-size: 0.92rem;
  outline: none; transition: border-color var(--t-fast);
  font-family: 'Plus Jakarta Sans', sans-serif;
}
.search-input-box input:focus { border-color: var(--primary); box-shadow: 0 0 0 3px var(--primary-100); }
.search-input-box input::placeholder { color: var(--text-muted); }

/* ========== BACK TO TOP ========== */
#back-top {
  position: fixed; bottom: 24px; right: 24px;
  width: 46px; height: 46px;
  background: var(--gradient-primary);
  color: white; border-radius: 50%;
  display: none; align-items: center; justify-content: center;
  cursor: pointer; z-index: 999;
  box-shadow: var(--shadow-primary);
  transition: all var(--t-normal);
  font-size: 1rem;
  border: none;
}
#back-top:hover { transform: translateY(-3px) scale(1.06); box-shadow: 0 12px 32px rgba(21,101,192,0.35); }

/* ========== ANIMATIONS ========== */
@keyframes fadeUp { from { opacity:0; transform: translateY(16px); } to { opacity:1; transform: translateY(0); } }
.animate-fade-in { animation: fadeUp 0.5s var(--ease) forwards; }

/* ========== MOBILE RESPONSIVE ========== */
@media (max-width:1100px) {
  #mobile-menu-btn { display: flex; }
  #main-nav {
    position: fixed;
    top: var(--header-h); left: 0;
    width: 100%; height: calc(100vh - var(--header-h));
    background: var(--bg-card);
    flex-direction: column; align-items: flex-start;
    padding: 16px;
    transform: translateX(-100%);
    transition: transform var(--t-normal);
    overflow-y: auto;
    border-top: 1px solid var(--border);
    box-shadow: var(--shadow-lg);
  }
  #main-nav.active { transform: translateX(0); }
  #main-nav ul { flex-direction: column; width: 100%; gap: 4px; }
  #main-nav li { width: 100%; }
  #main-nav > ul > li > a {
    justify-content: space-between; padding: 12px 16px;
    background: var(--bg-secondary);
    border: 1px solid var(--border);
  }
  .dropdown { position: static; opacity: 1; visibility: visible; transform: none; box-shadow: none; border: none; background: transparent; padding: 6px 0 6px 14px; display: none; margin: 0; }
  .dropdown::before { display: none; }
  .dropdown.show { display: block; }
  .dropdown a { background: var(--bg-secondary); margin-bottom: 4px; border: 1px solid var(--border); border-radius: var(--radius-sm); }
}

@media (max-width:768px) {
  .container { padding: 0 14px; }
  #site-header { padding: 0 14px; }
  .logo .brand-tagline { display: none; }
  #hero-section { margin-top: calc(var(--header-h) + 16px); padding-bottom: 24px; }
  .hero-title { font-size: 1.35rem; }
  .section-title { font-size: 1.5rem; }
  .post-card { padding: 18px; }
  .post-title { font-size: 1.4rem; }
  #back-top { bottom: 16px; right: 16px; width: 42px; height: 42px; }
  .comments .comment-block { margin-left: 0; padding: 12px; }
  .comments .avatar-image-container { margin-right: 8px; }
  .comments .avatar-image-container img { width: 34px; height: 34px; }
  .comments .comment .comment { margin-left: 16px; margin-top: 12px; padding-left: 12px; }
}

body.menu-open { overflow: hidden; }

@media (max-width: 680px) {
  #search-overlay { padding-top: 70px; padding-left: 14px; padding-right: 14px; }
  #search-box { padding: 20px 16px; }
  .filter-btns { gap: 6px; }
  .filter-btn { padding: 6px 12px; font-size: 0.75rem; }
}

@media (max-width: 480px) {
  .post-body pre { font-size: 0.72rem; padding: 12px; }
  .post-body code { font-size: 0.8em; word-break: break-all; }
  .post-body img { margin: 10px auto; border-radius: var(--radius-sm); }
}

@media (max-width: 400px) {
  body.item-view .post-card { padding: 14px 12px; }
  body.item-view .post-title { font-size: 1.15rem; }
  .hero-icon-large { width: 38px; height: 38px; font-size: 1.1rem; }
  .hero-title { font-size: 1.15rem; }
  .hero-card { padding: 18px 16px; }
  .hero-card h3 { font-size: 1rem; }
  .skd-card { padding: 20px 16px; }
  .skd-icon { width: 54px; height: 54px; font-size: 1.4rem; }
  .sponsor-card { padding: 20px 16px; }
  .section-header { margin-bottom: 24px; }
  .section-title { font-size: 1.3rem; }
  .post-card-content { padding: 14px 12px 16px; }
  .post-title-list { font-size: 1.05rem !important; }
  .post-snippet { font-size: 0.82rem; -webkit-line-clamp: 2; }
  .share-container { padding: 14px; }
  .btn-share { padding: 8px 12px; font-size: 0.75rem; }
  .sidebar-widget { padding: 16px; }
  .blog-pager a { padding: 9px 16px; font-size: 0.8rem; }
}

@supports (padding: env(safe-area-inset-bottom)) {
  #back-top { bottom: calc(24px + env(safe-area-inset-bottom)); }
  @media (max-width: 768px) { #back-top { bottom: calc(16px + env(safe-area-inset-bottom)); } }
}

/* Focus styles */
a:focus, button:focus, input:focus {
  outline: 2px solid var(--primary);
  outline-offset: 2px;
}

/* ========== PRINT ========== */
@media print {
  #site-header,#sidebar,#site-footer,#back-top,#search-overlay,#hero-section,#cpns-section,#sponsor-section { display: none !important; }
  body { background: white; color: #111; }
  .post-card { box-shadow: none; border: 1px solid #ddd; background: white; }
}

head.script:
//
(function(){
  var ogImg = document.querySelector('meta[property="og:image"]');
  if (!ogImg || !ogImg.content || ogImg.content.indexOf('YOUR_DEFAULT_BLOG_BANNER_IMAGE') > -1) {
    var title = document.title || 'Catatan Guru IPS';
    var safeTitle = title.replace(/[^a-zA-Z0-9\s\-\+\.]/g, '').replace(/\s+/g, '+').substring(0, 60);
    var fallbackUrl = 'https://og-image-generator.vercel.app/api/image?title=' + safeTitle + '&theme=light&fontFamily=Plus+Jakarta+Sans';
    if (!ogImg) {
      ogImg = document.createElement('meta');
      ogImg.setAttribute('property', 'og:image');
      document.head.appendChild(ogImg);
    }
    ogImg.setAttribute('content', fallbackUrl);
    var ogSecure = document.querySelector('meta[property="og:image:secure_url"]');
    if (ogSecure) ogSecure.setAttribute('content', fallbackUrl);
  }
  var twImg = document.querySelector('meta[name="twitter:image"]');
  if (!twImg || !twImg.content || twImg.content.indexOf('YOUR_DEFAULT_BLOG_BANNER_IMAGE') > -1) {
    var twUrl = ogImg ? ogImg.content : '';
    if (twUrl) {
      if (!twImg) {
        twImg = document.createElement('meta');
        twImg.setAttribute('name', 'twitter:image');
        document.head.appendChild(twImg);
      }
      twImg.setAttribute('content', twUrl);
    }
  }
})();
