// AUTO-EXTRACT FIRST IMAGE to Hero + OG Meta
(function() {
  if (!document.body.classList.contains('item-view')) return;
  var heroWrap = document.getElementById('post-hero-wrap');
  if (!heroWrap) return;
  if (heroWrap.querySelector('img')) return;

  function extractAndInjectHero() {
    var postBody = document.querySelector('.post-body');
    if (!postBody) return;
    var imgs = postBody.querySelectorAll('img');
    var srcUrl = null;
    for (var i = 0; i < imgs.length; i++) {
      var s = imgs[i].src || imgs[i].getAttribute('data-src') || '';
      if (!s) continue;
      var w = imgs[i].naturalWidth || imgs[i].width || 0;
      var h = imgs[i].naturalHeight || imgs[i].height || 0;
      if ((w > 0 && w < 80) || (h > 0 && h < 80)) continue;
      srcUrl = s; break;
    }
    if (!srcUrl) { heroWrap.style.display = ''; return; }
    srcUrl = srcUrl.replace(/\/s\d+(-[a-z])?\//, '/s1200/').replace('/s1600/', '/s1200/').replace('/s800/', '/s1200/').replace('/s400/', '/s1200/').replace('/s320/', '/s1200/');
    heroWrap.innerHTML = '<img src="' + srcUrl + '" alt="" class="post-hero-img-el" loading="eager"' + ' onerror="this.parentElement.style.display=\'none\'">';
    heroWrap.classList.remove('post-hero-generated');
    heroWrap.style.display = '';
    if (imgs[0]) {
      var firstWrapper = imgs[0].closest('figure, .separator, div') || imgs[0].parentElement;
      if (firstWrapper && firstWrapper.parentElement === postBody) { firstWrapper.style.display = 'none'; }
      else { imgs[0].style.display = 'none'; }
    }
    var ogImg = document.querySelector('meta[property="og:image"]');
    if (ogImg && (!ogImg.content || ogImg.content.indexOf('og-image-generator') > -1)) {
      ogImg.setAttribute('content', srcUrl);
      var ogS = document.querySelector('meta[property="og:image:secure_url"]');
      if (ogS) ogS.setAttribute('content', srcUrl);
      var twImg = document.querySelector('meta[name="twitter:image"]');
      if (twImg && (!twImg.content || twImg.content.indexOf('og-image-generator') > -1))
        twImg.setAttribute('content', srcUrl);
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', extractAndInjectHero);
  } else { extractAndInjectHero(); }
})();
