(function(){
  function ready(fn){
    if(document.readyState !== "loading"){
      fn();
    }else{
      document.addEventListener("DOMContentLoaded", fn);
    }
  }

  ready(function(){
    var menuButton = document.getElementById("mobile-menu-btn");
    var mainNav = document.getElementById("main-nav");
    var searchInput = document.getElementById("search-input");

    if(!document.querySelector("h1")){
      var h1 = document.createElement("h1");
      h1.className = "toer-visually-hidden";
      h1.textContent = "Catatan Guru IPS";
      document.body.insertBefore(h1, document.body.firstChild);
    }

    if(menuButton){
      if(mainNav){
        menuButton.setAttribute("aria-controls", "main-nav");
        menuButton.setAttribute("aria-expanded", mainNav.classList.contains("active") ? "true" : "false");

        menuButton.addEventListener("click", function(){
          setTimeout(function(){
            menuButton.setAttribute("aria-expanded", mainNav.classList.contains("active") ? "true" : "false");
          }, 0);
        });
      }
    }

    function runSearch(){
      if(!searchInput){
        return;
      }

      var q = searchInput.value.trim();

      if(!q){
        searchInput.focus();
        return;
      }

      window.location.href = "/search?q=" + encodeURIComponent(q);
    }

    if(searchInput){
      searchInput.addEventListener("keydown", function(e){
        if(e.key === "Enter"){
          e.preventDefault();
          runSearch();
        }
      });
    }

    document.querySelectorAll('[aria-label="Mulai pencarian"]').forEach(function(btn){
      btn.addEventListener("click", function(e){
        e.preventDefault();
        runSearch();
      });
    });

    document.querySelectorAll('nav a[href="#"]').forEach(function(link){
      link.setAttribute("role", "button");
      link.setAttribute("aria-expanded", "false");

      link.addEventListener("click", function(e){
        e.preventDefault();
      });
    });
  });
})();
